class Solution:
    def maximumBeauty(self, nums, k):
        nums = sorted(nums)
        n = len(nums)
        best = 0
        for i in range(n):
            cnt = 0
            for j in range(i, n):
                if nums[j] - nums[i] <= 2 * k:
                    cnt += 1
                else:
                    break
            best = max(best, cnt)
        return best

