class Solution:
    def maximumBeauty(self, nums, k):
        nums = sorted(nums)
        n = len(nums)
        left = 0
        best = 0
        for right in range(n):
            while nums[right] - nums[left] > 2 * k:
                left += 1
            best = max(best, right - left + 1)
        return best

