var maximumBeauty = function(nums, k) {
    const arr = nums.slice().sort((a, b) => a - b);
    const n = arr.length;
    let left = 0;
    let best = 0;
    for (let right = 0; right < n; right++) {
        while (arr[right] - arr[left] > 2 * k) {
            left++;
        }
        best = Math.max(best, right - left + 1);
    }
    return best;
};
